const express = require('express');
const router = express.Router();
const service = require('./service');
router.post('/', (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BadRequest', 'Name is required');
  const projectId = randomUUID();
  res.json({ project: { id: projectId, name: req.body.name } });
});
router.get('/:projectId/tasks', (req, res) => {
  if (!req.query.status) return sendError(res, 400, 'BadRequest', 'Status is required');
  const tasks = service.getTasksByProject(req.params.projectId);
  const filteredTasks = tasks.filter(task => task.status === req.query.status);
  res.json({ tasks: filteredTasks });
});
module.exports = router;

const projects = {};
const addProject = (projectId, name) => {
  if (!name) return null;
  projects[projectId] = { id: projectId, name };
};
const getTasksByProject = (projectId) => Object.values(projects).find(proj => proj.id === projectId)?.tasks || [];
module.exports = { addProject, getTasksByProject };

const express = require('express');
const router = express.Router({ mergeParams: true });
const service = require('./service');
router.post('/', (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BadRequest', 'Name is required');
  const taskId = randomUUID();
  const newTask = { id: taskId, name: req.body.name, status: 'todo' };
  service.addTaskToProject(req.params.projectId, newTask);
  res.json({ task: newTask });
});
router.patch('/:taskId', (req, res) => {
  const task = service.getTaskById(req.params.projectId, req.params.taskId);
  if (!task) return sendError(res, 404, 'NotFound', 'Task not found');
  if (['todo', 'done'].includes(req.body.status)) task.status = req.body.status;
  res.json({ task });
});
module.exports = router;

const tasks = {};
const addTaskToProject = (projectId, task) => {
  if (!task.name) return null;
  if (!['todo', 'done'].includes(task.status)) return null;
  if (!tasks[projectId]) tasks[projectId] = [];
  tasks[projectId].push(task);
};
const getTaskById = (projectId, taskId) => tasks[projectId]?.find(task => task.id === taskId);
module.exports = { addTaskToProject, getTaskById };

